query:
-- Check all inactive suppliers
SELECT id, name, isActive, updatedAt FROM suppliers WHERE isActive = 0 ORDER BY updatedAt DESC LIMIT 20;

-- Check suppliers updated in the last 2 hours
SELECT id, name, isActive, updatedAt FROM suppliers WHERE updatedAt > '2026-05-09 11:00:00' ORDER BY updatedAt DESC LIMIT 30;

